DROP TABLE IF EXISTS `college`;
CREATE TABLE `college` (
  `id` bigint NOT NULL COMMENT '学院代理主键（Snowflake）',
  `college_code` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '学院编号（业务码，可变更）',
  `college_name` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '学院名称',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识 0-正常 1-删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `college_code` (`college_code`) USING BTREE,
  UNIQUE KEY `uk_college_name` (`college_name`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='学院表';

DROP TABLE IF EXISTS `course`;
CREATE TABLE `course` (
  `id` bigint NOT NULL DEFAULT '0' COMMENT '课程代理主键（Snowflake）',
  `course_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '课程业务编码（如：COURSE_001）',
  `course_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '课程名',
  `college_id` bigint DEFAULT NULL COMMENT '开课学院',
  `course_nature` tinyint(1) NOT NULL COMMENT '课程性质（0:必修 1:选修）',
  `dict_id` bigint NOT NULL COMMENT '课程类别关联id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识（0:未删除 1:删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `idx_course_name_unique` (`course_name`) USING BTREE,
  KEY `fk_ course_dict_id` (`dict_id`) USING BTREE,
  CONSTRAINT `fk_ course_dict_id` FOREIGN KEY (`dict_id`) REFERENCES `sys_dict` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='课程表';

DROP TABLE IF EXISTS `course_exclusivity`;
CREATE TABLE `course_exclusivity` (
  `id` bigint NOT NULL COMMENT '分组代理主键（Snowflake）',
  `group_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分组编码',
  `training_program_id` bigint NOT NULL COMMENT '培养计划id',
  `required_credits` int unsigned DEFAULT NULL COMMENT '需选修够的学分',
  `version` int DEFAULT '1' COMMENT '版本号',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识（0:未删除 1:删除）',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_tp_id` (`training_program_id`) USING BTREE,
  CONSTRAINT `course_exclusivity_ibfk_1` FOREIGN KEY (`training_program_id`) REFERENCES `training_program` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='课程互斥/分组表';

DROP TABLE IF EXISTS `course_exclusivity_detail`;
CREATE TABLE `course_exclusivity_detail` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键Id',
  `course_id` bigint NOT NULL COMMENT '课程Id',
  `exclusivity_id` bigint NOT NULL COMMENT '分组Id',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识（0:未删除 1:删除）',
  PRIMARY KEY (`id`),
  KEY `idx_course_id` (`course_id`),
  KEY `idx_exclusivity_id` (`exclusivity_id`),
  CONSTRAINT `fk_detail_course` FOREIGN KEY (`course_id`) REFERENCES `course` (`id`),
  CONSTRAINT `fk_detail_exclusivity` FOREIGN KEY (`exclusivity_id`) REFERENCES `course_exclusivity` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2043591560463691777 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `major`;
CREATE TABLE `major` (
  `id` bigint NOT NULL COMMENT '专业代理主键',
  `major_code` char(4) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '专业代码（如 0809）',
  `major_name` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '专业名称',
  `college_id` bigint DEFAULT NULL COMMENT '所属学院ID',
  `course_num` int DEFAULT '0' COMMENT '课程总数',
  `category` tinyint(1) NOT NULL COMMENT '专业分类（0:工学 1:理学 2:文科）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_major_code_name` (`major_code`,`major_name`) USING BTREE,
  KEY `idx_college_id` (`college_id`) USING BTREE,
  KEY `idx_category_id` (`category`) USING BTREE,
  KEY `idx_del_flag` (`del_flag`) USING BTREE,
  CONSTRAINT `fk_major_college` FOREIGN KEY (`college_id`) REFERENCES `college` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='专业表';

DROP TABLE IF EXISTS `operation_log`;
CREATE TABLE `operation_log` (
  `id` bigint NOT NULL COMMENT '主键ID（Snowflake）',
  `operator_id` bigint NOT NULL COMMENT '操作人ID',
  `operator_name` varchar(128) NOT NULL COMMENT '操作人用户名',
  `operation_type` varchar(50) NOT NULL COMMENT '操作类型（如：RESET_PASSWORD）',
  `operation_desc` varchar(255) DEFAULT NULL COMMENT '操作描述',
  `target_user_id` bigint DEFAULT NULL COMMENT '目标用户ID',
  `target_username` varchar(128) DEFAULT NULL COMMENT '目标用户名',
  `ip_address` varchar(50) DEFAULT NULL COMMENT '操作IP地址',
  `result` tinyint(1) DEFAULT '1' COMMENT '操作结果（1:成功 0:失败）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识（0:未删除 1:删除）',
  PRIMARY KEY (`id`),
  KEY `idx_operator_id` (`operator_id`),
  KEY `idx_target_user_id` (`target_user_id`),
  KEY `idx_operation_type` (`operation_type`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='操作日志表';

DROP TABLE IF EXISTS `sys_dict`;
CREATE TABLE `sys_dict` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `dict_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '字典类型（如：course_type, user_state）',
  `dict_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '字典编码（程序内部引用，英文大写+下划线）',
  `dict_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '字典名称（用户界面显示）',
  `sort_order` int DEFAULT '0' COMMENT '排序号（控制下拉选项顺序）',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_dict_name` (`dict_name`) USING BTREE,
  UNIQUE KEY `uk_dict_type_code` (`dict_type`,`dict_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1988934871961915393 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='系统字典表（用于管理枚举值）';

DROP TABLE IF EXISTS `training_program`;
CREATE TABLE `training_program` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '培养计划名称',
  `major_id` bigint NOT NULL COMMENT '专业ID',
  `college_id` bigint NOT NULL COMMENT '学院ID',
  `year` int DEFAULT NULL COMMENT '年份',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '描述',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint DEFAULT '0' COMMENT '逻辑删除标记（0-未删除，1-已删除）',
  `current_version` int DEFAULT '1' COMMENT '当前版本号',
  `version_status` tinyint DEFAULT '0' COMMENT '版本状态（0:草稿 1:已发布）',
  `last_version_id` bigint DEFAULT NULL COMMENT '最新版本ID',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `fk_training_program_major_id` (`major_id`) USING BTREE,
  KEY `fk_training_program_college_id` (`college_id`) USING BTREE,
  KEY `idx_current_version` (`current_version`),
  KEY `idx_version_status` (`version_status`),
  KEY `idx_last_version_id` (`last_version_id`),
  CONSTRAINT `fk_training_program_college_id` FOREIGN KEY (`college_id`) REFERENCES `college` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_training_program_major_id` FOREIGN KEY (`major_id`) REFERENCES `major` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2043591389629689857 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='培养计划表';

DROP TABLE IF EXISTS `training_program_detail`;
CREATE TABLE `training_program_detail` (
  `id` bigint NOT NULL DEFAULT '0' COMMENT '课程代理主键（Snowflake）',
  `training_program_id` bigint NOT NULL COMMENT '培养计划id',
  `course_id` bigint NOT NULL COMMENT '课程id',
  `course_nature` tinyint NOT NULL COMMENT '课程性质（0:必修 1:选修）',
  `course_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '课程名',
  `college_id` bigint DEFAULT NULL COMMENT '开课学院ID（关联 college.id）',
  `major_id` bigint DEFAULT NULL COMMENT '修读专业ID（关联 major.id）',
  `total_credits` float(3,1) NOT NULL COMMENT '总学分',
  `total_hours` float(4,1) DEFAULT NULL COMMENT '总学时（小时）',
  `total_weeks` float(4,1) DEFAULT NULL COMMENT '总学时（周）',
  `hours_unit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '当前使用的学时单位（0:小时 1:周）',
  `hour_teach` int DEFAULT NULL COMMENT '授课学时',
  `hour_practice` int DEFAULT NULL COMMENT '实验学时',
  `hour_operation` int DEFAULT NULL COMMENT '上机学时',
  `hour_outside` int DEFAULT NULL COMMENT '实践学时',
  `hour_week` int DEFAULT NULL COMMENT '周学时',
  `term` tinyint(1) DEFAULT NULL COMMENT '建议修读学期',
  `required_elective` tinyint DEFAULT NULL COMMENT '选修学分要求',
  `course_choose_id` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '选修计划ID',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '备注',
  `version` int DEFAULT '1' COMMENT '版本号',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识（0:未删除 1:删除）',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `fk_training_program_detail_college` (`college_id`) USING BTREE,
  KEY `fk_training_program_detail_major` (`major_id`) USING BTREE,
  CONSTRAINT `fk_training_program_detail_college` FOREIGN KEY (`college_id`) REFERENCES `college` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_training_program_detail_major` FOREIGN KEY (`major_id`) REFERENCES `major` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='课程表';

DROP TABLE IF EXISTS `user`;
CREATE TABLE `user` (
  `id` bigint NOT NULL COMMENT '主键',
  `username` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户名',
  `password` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '密码',
  `college_id` bigint DEFAULT NULL COMMENT '所属学院ID（引用 college.id）',
  `dict_id` bigint DEFAULT NULL COMMENT '用户权限（关联字典表）',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标识',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `user_username_idx` (`username`) USING BTREE,
  KEY `idx_user_college_id` (`college_id`) USING BTREE,
  KEY `idx_user_dict_id` (`dict_id`) USING BTREE,
  CONSTRAINT `fk_user_college` FOREIGN KEY (`college_id`) REFERENCES `college` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_user_sys_dict` FOREIGN KEY (`dict_id`) REFERENCES `sys_dict` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='用户表';

DROP TABLE IF EXISTS `version_change_log`;
CREATE TABLE `version_change_log` (
  `id` bigint NOT NULL COMMENT '变更记录ID（Snowflake）',
  `version_id` bigint NOT NULL COMMENT '版本ID',
  `change_type` tinyint NOT NULL COMMENT '变更类型（1:新增 2:修改 3:删除）',
  `change_target` varchar(50) NOT NULL COMMENT '变更对象（course:课程 detail:课程详情）',
  `target_id` bigint DEFAULT NULL COMMENT '变更对象ID',
  `old_value` text COMMENT '变更前的值（JSON格式）',
  `new_value` text COMMENT '变更后的值（JSON格式）',
  `change_description` varchar(500) DEFAULT NULL COMMENT '变更描述',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_version_id` (`version_id`),
  KEY `idx_change_type` (`change_type`),
  KEY `idx_create_time` (`create_time`),
  CONSTRAINT `fk_change_log_version` FOREIGN KEY (`version_id`) REFERENCES `version_history` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='版本变更记录表';

DROP TABLE IF EXISTS `version_history`;
CREATE TABLE `version_history` (
  `id` bigint NOT NULL COMMENT '版本ID（Snowflake）',
  `training_program_id` bigint NOT NULL COMMENT '培养方案ID',
  `version_number` int NOT NULL COMMENT '版本号',
  `version_name` varchar(100) NOT NULL COMMENT '版本名称',
  `version_status` tinyint NOT NULL DEFAULT '0' COMMENT '版本状态（0:草稿 1:已发布 2:已归档 3:已回滚）',
  `change_description` text COMMENT '变更说明',
  `snapshot_data` longtext COMMENT '版本快照数据（JSON格式）',
  `creator_id` bigint NOT NULL COMMENT '创建人ID',
  `creator_name` varchar(50) NOT NULL COMMENT '创建人姓名',
  `publish_time` datetime DEFAULT NULL COMMENT '发布时间',
  `publish_user_id` bigint DEFAULT NULL COMMENT '发布人ID',
  `publish_user_name` varchar(50) DEFAULT NULL COMMENT '发布人姓名',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint DEFAULT '0' COMMENT '删除标识（0:未删除 1:已删除）',
  PRIMARY KEY (`id`),
  KEY `idx_training_program_id` (`training_program_id`),
  KEY `idx_version_number` (`version_number`),
  KEY `idx_version_status` (`version_status`),
  KEY `idx_create_time` (`create_time`),
  CONSTRAINT `fk_version_training_program` FOREIGN KEY (`training_program_id`) REFERENCES `training_program` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='版本历史表';

